{
  "name": "QReator Pro",
  "description": "A professional, highly customizable QR code generator with gradient support, custom shapes, logo integration, and high-resolution export options. Features AI-powered content suggestion."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum QRStyle {
  SQUARE = 'square',
  ROUNDED = 'rounded',
  DOTS = 'dots',
}

export enum EyeStyle {
  SQUARE = 'square',
  CIRCLE = 'circle',
}

export enum GradientType {
  NONE = 'none',
  LINEAR_VERTICAL = 'linear_vertical',
  LINEAR_HORIZONTAL = 'linear_horizontal',
  LINEAR_DIAGONAL = 'linear_diagonal', // "Corner" gradient
  RADIAL = 'radial',
}

export interface QRCodeConfig {
  value: string;
  size: number; // Export size
  quietZone: number;
  fgColor: string;
  fgColorEnd: string; // For gradient
  gradientType: GradientType;
  bgColor: string;
  bgEnabled: boolean;
  style: QRStyle;
  eyeStyle: EyeStyle;
  eyeColor: string | null; // null means match body
  logoUrl: string | null;
  logoSize: number; // 0.1 to 0.4
}

export const DEFAULT_CONFIG: QRCodeConfig = {
  value: 'https://example.com',
  size: 1000,
  quietZone: 2,
  fgColor: '#000000',
  fgColorEnd: '#4f46e5',
  gradientType: GradientType.NONE,
  bgColor: '#ffffff',
  bgEnabled: true,
  style: QRStyle.SQUARE,
  eyeStyle: EyeStyle.SQUARE,
  eyeColor: null,
  logoUrl: null,
  logoSize: 0.2,
};

import { GoogleGenAI } from "@google/genai";

// Helper to safely get the API key
const getApiKey = (): string | undefined => {
  return process.env.API_KEY;
};

export const generateCreativeContent = async (prompt: string): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a short, creative text snippet based on this request: "${prompt}". 
      Keep it under 200 characters. It will be used as content for a QR code. 
      Return ONLY the raw text, no markdown, no quotes.`,
    });

    return response.text.trim();
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate content.");
  }
};

import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import QRCode from 'qrcode';
import { QRCodeConfig, QRStyle, EyeStyle, GradientType } from '../types';

interface Props {
  config: QRCodeConfig;
  className?: string;
}

export interface QRCodeHandle {
  download: (format: 'png' | 'jpeg') => void;
}

const QRCodeRenderer = forwardRef<QRCodeHandle, Props>(({ config, className }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Expose download method
  useImperativeHandle(ref, () => ({
    download: (format) => {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const link = document.createElement('a');
      link.download = `qrcode-${Date.now()}.${format}`;
      link.href = canvas.toDataURL(`image/${format}`, 1.0);
      link.click();
    }
  }));

  useEffect(() => {
    const renderQR = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // 1. Generate QR Data Matrix
      // We render at a fixed internal resolution for the matrix calculations, 
      // but the actual canvas size is determined by config.size
      let qrData;
      try {
        qrData = QRCode.create(config.value || ' ', {
          errorCorrectionLevel: 'H', // High error correction to allow for logos
          margin: 0 // We handle margins manually
        });
      } catch (e) {
        console.error("QR Generation failed", e);
        return;
      }

      const moduleCount = qrData.modules.size;
      const size = config.size;
      const margin = config.bgEnabled ? config.quietZone * (size / moduleCount) : 0; 

      // Effective drawing area size
      const drawingSize = size - (margin * 2);
      const cellSize = drawingSize / moduleCount;

      // Reset Canvas
      canvas.width = size;
      canvas.height = size;
      ctx.clearRect(0, 0, size, size);

      // 2. Draw Background
      if (config.bgEnabled) {
        ctx.fillStyle = config.bgColor;
        ctx.fillRect(0, 0, size, size);
      }

      // 3. Prepare Gradients/Colors
      let fillStyle: string | CanvasGradient = config.fgColor;

      if (config.gradientType !== GradientType.NONE) {
        let gradient;
        if (config.gradientType === GradientType.LINEAR_VERTICAL) {
          gradient = ctx.createLinearGradient(0, margin, 0, size - margin);
        } else if (config.gradientType === GradientType.LINEAR_HORIZONTAL) {
          gradient = ctx.createLinearGradient(margin, 0, size - margin, 0);
        } else if (config.gradientType === GradientType.LINEAR_DIAGONAL) {
          gradient = ctx.createLinearGradient(margin, margin, size - margin, size - margin);
        } else { // RADIAL
          const center = size / 2;
          gradient = ctx.createRadialGradient(center, center, 0, center, center, size / 2);
        }

        gradient.addColorStop(0, config.fgColor);
        gradient.addColorStop(1, config.fgColorEnd);
        fillStyle = gradient;
      }

      // 4. Draw Modules
      const modules = qrData.modules.data;

      // Helper to identify position detection patterns (The 3 big eyes)
      const isEye = (row: number, col: number) => {
        // Top-Left
        if (row < 7 && col < 7) return true;
        // Top-Right
        if (row < 7 && col >= moduleCount - 7) return true;
        // Bottom-Left
        if (row >= moduleCount - 7 && col < 7) return true;
        return false;
      };

      for (let r = 0; r < moduleCount; r++) {
        for (let c = 0; c < moduleCount; c++) {
          const index = r * moduleCount + c;
          if (modules[index]) {
            const x = margin + c * cellSize;
            const y = margin + r * cellSize;

            const isEyeModule = isEye(r, c);

            // Set Color
            if (isEyeModule && config.eyeColor) {
               ctx.fillStyle = config.eyeColor;
            } else {
               ctx.fillStyle = fillStyle;
            }

            // Determine Shape
            let currentStyle = config.style;
            // Force square for eyes if requested, or if style is dots (eyes usually look better solid or specifically styled)
            if (isEyeModule) {
               if (config.eyeStyle === EyeStyle.CIRCLE) {
                 // For eyes, we handle them as blocks usually, but let's try to simulate the shape style
                 // Simplification: If eye style is circle, we might want to round the corners of the eye boxes
                 // But strictly checking per-module is hard.
                 // We will stick to the module shape mostly.
                 currentStyle = config.style === QRStyle.DOTS ? QRStyle.DOTS : QRStyle.ROUNDED;
               } else {
                 currentStyle = QRStyle.SQUARE;
               }
            }

            // Draw based on style
            ctx.beginPath();
            if (currentStyle === QRStyle.ROUNDED) {
              const radius = cellSize * 0.4;
              ctx.roundRect(x, y, cellSize, cellSize, radius);
            } else if (currentStyle === QRStyle.DOTS) {
              const radius = cellSize * 0.4; // leave some gaps
              const cx = x + cellSize / 2;
              const cy = y + cellSize / 2;
              ctx.arc(cx, cy, radius, 0, 2 * Math.PI);
            } else {
              // SQUARE
              // Fix for "thin white lines" artifact in canvas rendering: slightly overlap
              // Only overlap if solid blocks
              const overlap = 0.3; 
              ctx.rect(x, y, cellSize + overlap, cellSize + overlap);
            }
            ctx.fill();
          }
        }
      }

      // 5. Draw Logo
      if (config.logoUrl) {
        const logoImg = new Image();
        logoImg.crossOrigin = "Anonymous";
        logoImg.src = config.logoUrl;

        await new Promise((resolve) => {
          logoImg.onload = resolve;
          logoImg.onerror = resolve; // Continue even if logo fails
        });

        const logoSizePx = size * config.logoSize;
        const logoX = (size - logoSizePx) / 2;
        const logoY = (size - logoSizePx) / 2;

        // Draw white background for logo if background is enabled or to ensure contrast
        if (config.bgEnabled) {
            ctx.fillStyle = config.bgColor;
            // Round backing
            ctx.beginPath();
            ctx.roundRect(logoX - 5, logoY - 5, logoSizePx + 10, logoSizePx + 10, 10);
            ctx.fill();
        }

        ctx.drawImage(logoImg, logoX, logoY, logoSizePx, logoSizePx);
      }
    };

    renderQR();
  }, [config]);

  return (
    <canvas 
      ref={canvasRef} 
      className={className}
      style={{ maxWidth: '100%', height: 'auto', display: 'block' }}
    />
  );
});

QRCodeRenderer.displayName = "QRCodeRenderer";
export default QRCodeRenderer;

import React from 'react';

interface Props {
  label: string;
  color: string;
  onChange: (color: string) => void;
  className?: string;
  disabled?: boolean;
}

export const ColorPicker: React.FC<Props> = ({ label, color, onChange, className, disabled }) => {
  return (
    <div className={`flex flex-col gap-1 ${className} ${disabled ? 'opacity-50 pointer-events-none' : ''}`}>
      <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">{label}</span>
      <div className="flex items-center gap-2 bg-white border border-gray-200 p-1.5 rounded-lg shadow-sm">
        <input 
          type="color" 
          value={color}
          onChange={(e) => onChange(e.target.value)}
          className="w-8 h-8 rounded cursor-pointer border-none bg-transparent p-0"
        />
        <input 
          type="text" 
          value={color} 
          onChange={(e) => onChange(e.target.value)}
          className="flex-1 text-sm font-mono text-gray-700 outline-none uppercase"
          maxLength={7}
        />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { QRCodeConfig, QRStyle, EyeStyle, GradientType } from '../types';
import { ColorPicker } from './ColorPicker';
import { generateCreativeContent } from '../services/geminiService';
import { 
  Type, Palette, Layers, Image as ImageIcon, Download, Sparkles, 
  AlignLeft, Grid, Circle, Square, Loader2 
} from 'lucide-react';

interface Props {
  config: QRCodeConfig;
  setConfig: React.Dispatch<React.SetStateAction<QRCodeConfig>>;
  onDownload: (format: 'png' | 'jpeg') => void;
}

const Sidebar: React.FC<Props> = ({ config, setConfig, onDownload }) => {
  const [activeTab, setActiveTab] = useState<'content' | 'style' | 'logo' | 'export'>('content');
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const text = await generateCreativeContent(aiPrompt);
      setConfig(prev => ({ ...prev, value: text }));
    } catch (error) {
      alert("Failed to generate content. Check API key or connection.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        if (ev.target?.result) {
          setConfig(prev => ({ ...prev, logoUrl: ev.target!.result as string }));
        }
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white border-r border-gray-200 overflow-y-auto">
      {/* Mobile Tab Bar (visible only on small screens, usually sticky top or bottom, but here we keep it simple for responsive layout in parent) */}
      <div className="flex md:flex-col border-b md:border-b-0 md:border-r border-gray-200">
        <button 
          onClick={() => setActiveTab('content')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'content' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <Type size={20} />
          Content
        </button>
        <button 
          onClick={() => setActiveTab('style')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'style' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <Palette size={20} />
          Style
        </button>
        <button 
          onClick={() => setActiveTab('logo')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'logo' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <ImageIcon size={20} />
          Logo
        </button>
        <button 
          onClick={() => setActiveTab('export')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'export' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <Download size={20} />
          Export
        </button>
      </div>

      <div className="p-6 space-y-8 flex-1">

        {/* CONTENT TAB */}
        {activeTab === 'content' && (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Data / URL</label>
              <textarea
                value={config.value}
                onChange={(e) => setConfig({ ...config, value: e.target.value })}
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all h-32 resize-none text-sm"
                placeholder="https://yourwebsite.com"
              />
            </div>

            <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100">
              <div className="flex items-center gap-2 mb-3 text-indigo-700">
                <Sparkles size={16} />
                <span className="text-sm font-bold">AI Content Wizard</span>
              </div>
              <p className="text-xs text-indigo-600 mb-3">Ask Gemini to create a message for you.</p>
              <div className="flex gap-2">
                <input 
                  type="text"
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  placeholder="e.g. A romantic poem about coffee"
                  className="flex-1 text-sm p-2 rounded border border-indigo-200 focus:outline-none"
                />
                <button 
                  onClick={handleAiGenerate}
                  disabled={isGenerating || !process.env.API_KEY}
                  className="bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isGenerating ? <Loader2 className="animate-spin" size={16} /> : 'Go'}
                </button>
              </div>
              {!process.env.API_KEY && (
                <p className="text-[10px] text-red-500 mt-2">API Key missing in environment.</p>
              )}
            </div>
          </div>
        )}

        {/* STYLE TAB */}
        {activeTab === 'style' && (
          <div className="space-y-8">
            {/* Color Section */}
            <section className="space-y-4">
              <h3 className="text-sm font-bold text-gray-900 flex items-center gap-2 pb-2 border-b">
                <Palette size={16} /> Colors
              </h3>

              <div className="space-y-3">
                <div className="flex items-center justify-between">
                   <label className="text-sm text-gray-600">Gradient Type</label>
                   <select 
                     value={config.gradientType}
                     onChange={(e) => setConfig({...config, gradientType: e.target.value as GradientType})}
                     className="text-sm border rounded p-1"
                   >
                     <option value={GradientType.NONE}>Solid</option>
                     <option value={GradientType.LINEAR_VERTICAL}>Vertical</option>
                     <option value={GradientType.LINEAR_HORIZONTAL}>Horizontal</option>
                     <option value={GradientType.LINEAR_DIAGONAL}>Diagonal</option>
                     <option value={GradientType.RADIAL}>Radial</option>
                   </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <ColorPicker 
                    label="Foreground" 
                    color={config.fgColor} 
                    onChange={(c) => setConfig({...config, fgColor: c})} 
                  />
                  <ColorPicker 
                    label="End Color" 
                    color={config.fgColorEnd} 
                    onChange={(c) => setConfig({...config, fgColorEnd: c})}
                    disabled={config.gradientType === GradientType.NONE} 
                  />
                </div>

                <div className="pt-2 border-t border-dashed"></div>

                <div className="flex items-center justify-between mb-2">
                   <label className="text-sm text-gray-600">Background</label>
                   <input 
                     type="checkbox" 
                     checked={config.bgEnabled}
                     onChange={(e) => setConfig({...config, bgEnabled: e.target.checked})}
                     className="accent-indigo-600"
                   />
                </div>
                <ColorPicker 
                  label="BG Color" 
                  color={config.bgColor} 
                  onChange={(c) => setConfig({...config, bgColor: c})}
                  disabled={!config.bgEnabled}
                />
              </div>
            </section>

            {/* Shape Section */}
            <section className="space-y-4">
              <h3 className="text-sm font-bold text-gray-900 flex items-center gap-2 pb-2 border-b">
                <Layers size={16} /> Shapes
              </h3>

              <div className="space-y-4">
                <div>
                  <label className="text-xs text-gray-500 uppercase tracking-wide mb-2 block">Body Style</label>
                  <div className="grid grid-cols-3 gap-2">
                    {[
                      { id: QRStyle.SQUARE, icon: <Square size={16} />, label: 'Square' },
                      { id: QRStyle.ROUNDED, icon: <Square size={16} className="rounded-sm" />, label: 'Rounded' },
                      { id: QRStyle.DOTS, icon: <Circle size={16} />, label: 'Dots' },
                    ].map((style) => (
                      <button
                        key={style.id}
                        onClick={() => setConfig({...config, style: style.id as QRStyle})}
                        className={`flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${config.style === style.id ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-200 hover:border-gray-300'}`}
                      >
                        {style.icon}
                        <span className="text-[10px] mt-1">{style.label}</span>
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                   <label className="text-xs text-gray-500 uppercase tracking-wide mb-2 block">Eye Style</label>
                   <div className="grid grid-cols-2 gap-2">
                      <button
                        onClick={() => setConfig({...config, eyeStyle: EyeStyle.SQUARE})}
                        className={`p-2 rounded-lg border text-sm ${config.eyeStyle === EyeStyle.SQUARE ? 'border-indigo-600 bg-indigo-50' : 'border-gray-200'}`}
                      >
                        Square Frame
                      </button>
                      <button
                        onClick={() => setConfig({...config, eyeStyle: EyeStyle.CIRCLE})}
                        className={`p-2 rounded-lg border text-sm ${config.eyeStyle === EyeStyle.CIRCLE ? 'border-indigo-600 bg-indigo-50' : 'border-gray-200'}`}
                      >
                        Circle Frame
                      </button>
                   </div>
                </div>

                <div>
                   <label className="flex items-center gap-2">
                      <input 
                        type="checkbox" 
                        checked={config.eyeColor !== null}
                        onChange={(e) => setConfig({...config, eyeColor: e.target.checked ? '#000000' : null})}
                        className="accent-indigo-600"
                      />
                      <span className="text-sm text-gray-700">Custom Eye Color</span>
                   </label>
                   {config.eyeColor !== null && (
                      <div className="mt-2">
                        <ColorPicker 
                          label="Eye Color" 
                          color={config.eyeColor} 
                          onChange={(c) => setConfig({...config, eyeColor: c})}
                        />
                      </div>
                   )}
                </div>
              </div>
            </section>
          </div>
        )}

        {/* LOGO TAB */}
        {activeTab === 'logo' && (
          <div className="space-y-6">
            <div className="bg-gray-50 border-2 border-dashed border-gray-300 rounded-xl p-8 text-center hover:bg-gray-100 transition-colors relative">
               <input 
                 type="file" 
                 accept="image/*"
                 onChange={handleLogoUpload}
                 className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
               />
               <div className="flex flex-col items-center text-gray-500">
                 <ImageIcon size={32} className="mb-2" />
                 <span className="text-sm font-medium">Click to upload logo</span>
                 <span className="text-xs text-gray-400 mt-1">PNG, JPG recommended</span>
               </div>
            </div>

            {config.logoUrl && (
              <div className="space-y-4">
                 <div className="flex items-center gap-4 p-3 bg-white border rounded-lg shadow-sm">
                    <img src={config.logoUrl} alt="Logo" className="w-12 h-12 object-contain" />
                    <button 
                      onClick={() => setConfig({...config, logoUrl: null})}
                      className="text-xs text-red-600 hover:text-red-700 font-medium"
                    >
                      Remove
                    </button>
                 </div>

                 <div>
                    <label className="text-xs text-gray-500 uppercase tracking-wide mb-2 block">Logo Size</label>
                    <input 
                      type="range"
                      min="0.1"
                      max="0.4"
                      step="0.05"
                      value={config.logoSize}
                      onChange={(e) => setConfig({...config, logoSize: parseFloat(e.target.value)})}
                      className="w-full accent-indigo-600 h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer"
                    />
                 </div>
              </div>
            )}
          </div>
        )}

        {/* EXPORT TAB */}
        {activeTab === 'export' && (
          <div className="space-y-6">
             <div>
                <label className="flex justify-between text-sm text-gray-700 mb-2">
                   <span>Dimensions</span>
                   <span className="font-mono text-gray-500">{config.size}px</span>
                </label>
                <input 
                  type="range"
                  min="250"
                  max="1500"
                  step="50"
                  value={config.size}
                  onChange={(e) => setConfig({...config, size: parseInt(e.target.value)})}
                  className="w-full accent-indigo-600 h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer mb-2"
                />
                <div className="flex justify-between text-[10px] text-gray-400">
                   <span>250px</span>
                   <span>1500px</span>
                </div>
             </div>

             <div className="space-y-3">
                <button 
                  onClick={() => onDownload('png')}
                  className="w-full py-3 px-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg shadow-indigo-200 font-medium flex items-center justify-center gap-2 transition-all"
                >
                  <Download size={18} /> Download PNG
                </button>
                <button 
                  onClick={() => onDownload('jpeg')}
                  className="w-full py-3 px-4 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 rounded-xl font-medium flex items-center justify-center gap-2 transition-all"
                >
                  <Download size={18} /> Download JPEG
                </button>
             </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useRef } from 'react';
import Sidebar from './components/Sidebar';
import QRCodeRenderer, { QRCodeHandle } from './components/QRCodeRenderer';
import { QRCodeConfig, DEFAULT_CONFIG } from './types';
import { QrCode, Share2 } from 'lucide-react';

const App = () => {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const qrRef = useRef<QRCodeHandle>(null);

  const handleDownload = (format: 'png' | 'jpeg') => {
    qrRef.current?.download(format);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
      {/* Sidebar Controls */}
      <div className="w-full md:w-[400px] flex-shrink-0 h-[50vh] md:h-screen sticky top-0 md:static z-20 shadow-xl md:shadow-none order-2 md:order-1">
        <Sidebar 
          config={config} 
          setConfig={setConfig} 
          onDownload={handleDownload} 
        />
      </div>

      {/* Main Preview Area */}
      <div className="flex-1 flex flex-col h-[50vh] md:h-screen overflow-hidden order-1 md:order-2 bg-slate-100 relative">
        {/* Header */}
