export enum QRStyle {
  SQUARE = 'square',
  ROUNDED = 'rounded',
  DOTS = 'dots',
  SQUARE_DOTS = 'square_dots',
}

export enum EyeStyle {
  SQUARE = 'square',
  CIRCLE = 'circle',
}

export enum GradientType {
  NONE = 'none',
  LINEAR_VERTICAL = 'linear_vertical',
  LINEAR_HORIZONTAL = 'linear_horizontal',
  LINEAR_DIAGONAL = 'linear_diagonal', // "Corner" gradient
  RADIAL = 'radial',
}

export interface QRCodeConfig {
  value: string;
  size: number; // Export size
  quietZone: number;
  fgColor: string;
  fgColorEnd: string; // For gradient
  gradientType: GradientType;
  bgColor: string;
  bgEnabled: boolean;
  style: QRStyle;
  eyeStyle: EyeStyle;
  eyeColor: string | null; // null means match body
  logoUrl: string | null;
  logoSize: number; // 0.1 to 0.4
}

export const DEFAULT_CONFIG: QRCodeConfig = {
  value: 'https://example.com',
  size: 1000,
  quietZone: 2,
  fgColor: '#000000',
  fgColorEnd: '#4f46e5',
  gradientType: GradientType.NONE,
  bgColor: '#ffffff',
  bgEnabled: true,
  style: QRStyle.SQUARE,
  eyeStyle: EyeStyle.SQUARE,
  eyeColor: null,
  logoUrl: null,
  logoSize: 0.2,
};

import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import QRCode from 'qrcode';
import { QRCodeConfig, QRStyle, EyeStyle, GradientType } from '../types';

interface Props {
  config: QRCodeConfig;
  className?: string;
}

export interface QRCodeHandle {
  download: (format: 'png' | 'jpeg') => void;
}

const QRCodeRenderer = forwardRef<QRCodeHandle, Props>(({ config, className }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Expose download method
  useImperativeHandle(ref, () => ({
    download: (format) => {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const link = document.createElement('a');
      link.download = `qrcode-${Date.now()}.${format}`;
      link.href = canvas.toDataURL(`image/${format}`, 1.0);
      link.click();
    }
  }));

  useEffect(() => {
    const renderQR = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // 1. Generate QR Data Matrix
      // We render at a fixed internal resolution for the matrix calculations, 
      // but the actual canvas size is determined by config.size
      let qrData;
      try {
        qrData = QRCode.create(config.value || ' ', {
          errorCorrectionLevel: 'H', // High error correction to allow for logos
          margin: 0 // We handle margins manually
        });
      } catch (e) {
        console.error("QR Generation failed", e);
        return;
      }

      const moduleCount = qrData.modules.size;
      const size = config.size;
      const margin = config.bgEnabled ? config.quietZone * (size / moduleCount) : 0; 

      // Effective drawing area size
      const drawingSize = size - (margin * 2);
      const cellSize = drawingSize / moduleCount;

      // Reset Canvas
      canvas.width = size;
      canvas.height = size;
      ctx.clearRect(0, 0, size, size);

      // 2. Draw Background
      if (config.bgEnabled) {
        ctx.fillStyle = config.bgColor;
        ctx.fillRect(0, 0, size, size);
      }

      // 3. Prepare Gradients/Colors
      let fillStyle: string | CanvasGradient = config.fgColor;

      if (config.gradientType !== GradientType.NONE) {
        let gradient;
        if (config.gradientType === GradientType.LINEAR_VERTICAL) {
          gradient = ctx.createLinearGradient(0, margin, 0, size - margin);
        } else if (config.gradientType === GradientType.LINEAR_HORIZONTAL) {
          gradient = ctx.createLinearGradient(margin, 0, size - margin, 0);
        } else if (config.gradientType === GradientType.LINEAR_DIAGONAL) {
          gradient = ctx.createLinearGradient(margin, margin, size - margin, size - margin);
        } else { // RADIAL
          const center = size / 2;
          gradient = ctx.createRadialGradient(center, center, 0, center, center, size / 2);
        }

        gradient.addColorStop(0, config.fgColor);
        gradient.addColorStop(1, config.fgColorEnd);
        fillStyle = gradient;
      }

      // 4. Draw Modules
      const modules = qrData.modules.data;

      // Helper to identify position detection patterns (The 3 big eyes)
      const isEye = (row: number, col: number) => {
        // Top-Left
        if (row < 7 && col < 7) return true;
        // Top-Right
        if (row < 7 && col >= moduleCount - 7) return true;
        // Bottom-Left
        if (row >= moduleCount - 7 && col < 7) return true;
        return false;
      };

      for (let r = 0; r < moduleCount; r++) {
        for (let c = 0; c < moduleCount; c++) {
          const index = r * moduleCount + c;
          if (modules[index]) {
            const x = margin + c * cellSize;
            const y = margin + r * cellSize;

            const isEyeModule = isEye(r, c);

            // Set Color
            if (isEyeModule && config.eyeColor) {
               ctx.fillStyle = config.eyeColor;
            } else {
               ctx.fillStyle = fillStyle;
            }

            // Determine Shape
            let currentStyle = config.style;

            // Handle Eye Logic
            if (isEyeModule) {
               if (config.eyeStyle === EyeStyle.CIRCLE) {
                 // Map to appropriate rounded/dot style for eyes
                 currentStyle = config.style === QRStyle.DOTS ? QRStyle.DOTS : QRStyle.ROUNDED;
               } else {
                 currentStyle = QRStyle.SQUARE;
               }
            }

            // Draw based on style
            ctx.beginPath();
            if (currentStyle === QRStyle.ROUNDED) {
              const radius = cellSize * 0.4;
              ctx.roundRect(x, y, cellSize, cellSize, radius);
            } else if (currentStyle === QRStyle.DOTS) {
              const radius = cellSize * 0.4; // leave some gaps
              const cx = x + cellSize / 2;
              const cy = y + cellSize / 2;
              ctx.arc(cx, cy, radius, 0, 2 * Math.PI);
            } else if (currentStyle === QRStyle.SQUARE_DOTS) {
              // Square with gaps (Pixels)
              const scale = 0.8;
              const size = cellSize * scale;
              const offset = (cellSize - size) / 2;
              ctx.rect(x + offset, y + offset, size, size);
            } else {
              // SQUARE
              // Fix for "thin white lines" artifact in canvas rendering: slightly overlap
              // Only overlap if solid blocks
              const overlap = 0.3; 
              ctx.rect(x, y, cellSize + overlap, cellSize + overlap);
            }
            ctx.fill();
          }
        }
      }

      // 5. Draw Logo
      if (config.logoUrl) {
        const logoImg = new Image();
        logoImg.crossOrigin = "Anonymous";
        logoImg.src = config.logoUrl;

        await new Promise((resolve) => {
          logoImg.onload = resolve;
          logoImg.onerror = resolve; // Continue even if logo fails
        });

        const logoSizePx = size * config.logoSize;
        const logoX = (size - logoSizePx) / 2;
        const logoY = (size - logoSizePx) / 2;

        // Draw white background for logo if background is enabled or to ensure contrast
        if (config.bgEnabled) {
            ctx.fillStyle = config.bgColor;
            // Round backing
            ctx.beginPath();
            ctx.roundRect(logoX - 5, logoY - 5, logoSizePx + 10, logoSizePx + 10, 10);
            ctx.fill();
        }

        ctx.drawImage(logoImg, logoX, logoY, logoSizePx, logoSizePx);
      }
    };

    renderQR();
  }, [config]);

  return (
    <canvas 
      ref={canvasRef} 
      className={className}
      style={{ maxWidth: '100%', height: 'auto', display: 'block' }}
    />
  );
});

QRCodeRenderer.displayName = "QRCodeRenderer";
export default QRCodeRenderer;

import React, { useState } from 'react';
import { QRCodeConfig, QRStyle, EyeStyle, GradientType } from '../types';
import { ColorPicker } from './ColorPicker';
import { generateCreativeContent } from '../services/geminiService';
import { 
  Type, Palette, Layers, Image as ImageIcon, Download, Sparkles, 
  AlignLeft, Grid, Circle, Square, Loader2 
} from 'lucide-react';

interface Props {
  config: QRCodeConfig;
  setConfig: React.Dispatch<React.SetStateAction<QRCodeConfig>>;
  onDownload: (format: 'png' | 'jpeg') => void;
}

const Sidebar: React.FC<Props> = ({ config, setConfig, onDownload }) => {
  const [activeTab, setActiveTab] = useState<'content' | 'style' | 'logo' | 'export'>('content');
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const text = await generateCreativeContent(aiPrompt);
      setConfig(prev => ({ ...prev, value: text }));
    } catch (error) {
      alert("Failed to generate content. Check API key or connection.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        if (ev.target?.result) {
          setConfig(prev => ({ ...prev, logoUrl: ev.target!.result as string }));
        }
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white border-r border-gray-200 overflow-y-auto">
      {/* Mobile Tab Bar (visible only on small screens, usually sticky top or bottom, but here we keep it simple for responsive layout in parent) */}
      <div className="flex md:flex-col border-b md:border-b-0 md:border-r border-gray-200">
        <button 
          onClick={() => setActiveTab('content')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'content' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <Type size={20} />
          Content
        </button>
        <button 
          onClick={() => setActiveTab('style')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'style' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <Palette size={20} />
          Style
        </button>
        <button 
          onClick={() => setActiveTab('logo')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'logo' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <ImageIcon size={20} />
          Logo
        </button>
        <button 
          onClick={() => setActiveTab('export')}
          className={`flex-1 md:flex-none p-4 flex flex-col items-center gap-1 text-xs font-medium transition-colors ${activeTab === 'export' ? 'text-indigo-600 bg-indigo-50 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <Download size={20} />
          Export
        </button>
      </div>

      <div className="p-6 space-y-8 flex-1">

        {/* CONTENT TAB */}
        {activeTab === 'content' && (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Data / URL</label>
              <textarea
                value={config.value}
                onChange={(e) => setConfig({ ...config, value: e.target.value })}
