                    onChange={(c) => setConfig({...config, fgColor: c})} 
                  />
                  <ColorPicker 
                    label="End Color" 
                    color={config.fgColorEnd} 
                    onChange={(c) => setConfig({...config, fgColorEnd: c})}
                    disabled={config.gradientType === GradientType.NONE} 
