                     checked={config.bgEnabled}
                     onChange={(e) => setConfig({...config, bgEnabled: e.target.checked})}
                     className="accent-indigo-600"
                   />
                </div>
                <ColorPicker 
                  label="BG Color" 
                  color={config.bgColor} 
                  onChange={(c) => setConfig({...config, bgColor: c})}
                  disabled={!config.bgEnabled}
                />
              </div>
            </section>

            {/* Shape Section */}
            <section className="space-y-4">
              <h3 className="text-sm font-bold text-gray-900 flex items-center gap-2 pb-2 border-b">
                <Layers size={16} /> Shapes
              </h3>

              <div className="space-y-4">
                <div>
                  <label className="text-xs text-gray-500 uppercase tracking-wide mb-2 block">Body Style</label>
                  <div className="grid grid-cols-2 gap-2">
                    {[
                      { id: QRStyle.SQUARE, icon: <Square size={16} />, label: 'Square' },
                      { id: QRStyle.ROUNDED, icon: <Square size={16} className="rounded-sm" />, label: 'Rounded' },
                      { id: QRStyle.DOTS, icon: <Circle size={16} />, label: 'Dots' },
                      { id: QRStyle.SQUARE_DOTS, icon: <Grid size={16} />, label: 'Pixels' },
                    ].map((style) => (
                      <button
