                        onClick={() => setConfig({...config, style: style.id as QRStyle})}
                        className={`flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${config.style === style.id ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-200 hover:border-gray-300'}`}
                      >
                        {style.icon}
                        <span className="text-[10px] mt-1">{style.label}</span>
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                   <label className="text-xs text-gray-500 uppercase tracking-wide mb-2 block">Eye Style</label>
                   <div className="grid grid-cols-2 gap-2">
                      <button
                        onClick={() => setConfig({...config, eyeStyle: EyeStyle.SQUARE})}
                        className={`p-2 rounded-lg border text-sm ${config.eyeStyle === EyeStyle.SQUARE ? 'border-indigo-600 bg-indigo-50' : 'border-gray-200'}`}
                      >
                        Square Frame
                      </button>
                      <button
                        onClick={() => setConfig({...config, eyeStyle: EyeStyle.CIRCLE})}
                        className={`p-2 rounded-lg border text-sm ${config.eyeStyle === EyeStyle.CIRCLE ? 'border-indigo-600 bg-indigo-50' : 'border-gray-200'}`}
                      >
                        Circle Frame
                      </button>
                   </div>
                </div>

                <div>
                   <label className="flex items-center gap-2">
                      <input 
                        type="checkbox" 
                        checked={config.eyeColor !== null}
                        onChange={(e) => setConfig({...config, eyeColor: e.target.checked ? '#000000' : null})}
                        className="accent-indigo-600"
                      />
                      <span className="text-sm text-gray-700">Custom Eye Color</span>
                   </label>
                   {config.eyeColor !== null && (
                      <div className="mt-2">
                        <ColorPicker 
                          label="Eye Color" 
                          color={config.eyeColor} 
                          onChange={(c) => setConfig({...config, eyeColor: c})}
                        />
                      </div>
                   )}
                </div>
              </div>
            </section>
          </div>
        )}

        {/* LOGO TAB */}
        {activeTab === 'logo' && (
          <div className="space-y-6">
            <div className="bg-gray-50 border-2 border-dashed border-gray-300 rounded-xl p-8 text-center hover:bg-gray-100 transition-colors relative">
               <input 
                 type="file" 
                 accept="image/*"
                 onChange={handleLogoUpload}
                 className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
               />
               <div className="flex flex-col items-center text-gray-500">
                 <ImageIcon size={32} className="mb-2" />
                 <span className="text-sm font-medium">Click to upload logo</span>
                 <span className="text-xs text-gray-400 mt-1">PNG, JPG recommended</span>
               </div>
            </div>

            {config.logoUrl && (
              <div className="space-y-4">
                 <div className="flex items-center gap-4 p-3 bg-white border rounded-lg shadow-sm">
                    <img src={config.logoUrl} alt="Logo" className="w-12 h-12 object-contain" />
                    <button 
                      onClick={() => setConfig({...config, logoUrl: null})}
                      className="text-xs text-red-600 hover:text-red-700 font-medium"
                    >
                      Remove
                    </button>
                 </div>

                 <div>
                    <label className="text-xs text-gray-500 uppercase tracking-wide mb-2 block">Logo Size</label>
                    <input 
                      type="range"
