export default Sidebar;

export enum QRType {
  WEBSITE = 'website',
  TEXT = 'text',
  WIFI = 'wifi',
  VCARD = 'vcard',
  // Simplified list for this demo, can be expanded
}

export enum QRStyle {
  SQUARE = 'square',
  ROUNDED = 'rounded',
  DOTS = 'dots',
  DIAMOND = 'diamond',
  HEART = 'heart',
}

export enum CornerSquareStyle {
  SQUARE = 'square',
  DOT = 'dot', // Circle
  EXTRA_ROUNDED = 'extra_rounded',
}

export enum CornerDotStyle {
  SQUARE = 'square',
  DOT = 'dot',
  DIAMOND = 'diamond',
}

export enum GradientType {
  NONE = 'none',
  LINEAR_VERTICAL = 'linear_vertical',
  LINEAR_HORIZONTAL = 'linear_horizontal',
  RADIAL = 'radial',
}

export interface QRCodeConfig {
  type: QRType;
  value: string;
  size: number;

  // Pattern (Body)
  style: QRStyle;
  fgColor: string;
  gradientType: GradientType;
  fgColorEnd: string; // Used if gradient is active

  // Background
  bgEnabled: boolean;
  bgColor: string;

  // Corners (Eyes)
  cornerSquareStyle: CornerSquareStyle;
  cornerSquareColor: string | null; // null = use fgColor

  cornerDotStyle: CornerDotStyle;
  cornerDotColor: string | null; // null = use fgColor

