               <div className="text-center text-xs text-slate-400 mt-1">{config.size} x {config.size} px</div>
             </div>

             <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => onDownload('png')} 
                  className="bg-blue-600 text-white py-3 rounded-xl font-bold text-sm hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200"
                >
                   Download PNG
                </button>
                <button 
                   onClick={() => onDownload('jpeg')} 
                   className="bg-white border border-slate-200 text-slate-700 py-3 rounded-xl font-bold text-sm hover:bg-slate-50 transition-colors"
                >
                   Download JPG
                </button>
             </div>
          </section>

        </div>
      </div>
    </div>
  );
}

