export default App;

export enum QRType {
  WEBSITE = 'website',
  PDF = 'pdf',
  LIST_LINKS = 'list_links',
  VCARD = 'vcard',
  BUSINESS = 'business',
  VIDEO = 'video',
  IMAGES = 'images',
  FACEBOOK = 'facebook',
  INSTAGRAM = 'instagram',
  SOCIAL_MEDIA = 'social_media',
  WHATSAPP = 'whatsapp',
  MP3 = 'mp3',
  MENU = 'menu',
  APPS = 'apps',
  COUPON = 'coupon',
  WIFI = 'wifi',
  TEXT = 'text'
}

export enum QRStyle {
  SQUARE = 'square',
  ROUNDED = 'rounded',
  DOTS = 'dots',
  DIAMOND = 'diamond',
  HEART = 'heart',
}

export enum CornerSquareStyle {
  SQUARE = 'square',
  DOT = 'dot', // Circle
  EXTRA_ROUNDED = 'extra_rounded',
}

export enum CornerDotStyle {
  SQUARE = 'square',
  DOT = 'dot',
  DIAMOND = 'diamond',
}

export enum GradientType {
  NONE = 'none',
  LINEAR_VERTICAL = 'linear_vertical',
  LINEAR_HORIZONTAL = 'linear_horizontal',
  RADIAL = 'radial',
}

export interface QRCodeConfig {
  type: QRType;
  value: string;
  size: number;

  // Pattern (Body)
  style: QRStyle;
  fgColor: string;
  gradientType: GradientType;
  fgColorEnd: string; // Used if gradient is active

  // Background
  bgEnabled: boolean;
  bgColor: string;

  // Corners (Eyes)
  cornerSquareStyle: CornerSquareStyle;
  cornerSquareColor: string | null; // null = use fgColor

  cornerDotStyle: CornerDotStyle;
  cornerDotColor: string | null; // null = use fgColor

  // Logo
  logoUrl: string | null;
  logoSize: number;
}

export const DEFAULT_CONFIG: QRCodeConfig = {
  type: QRType.WEBSITE,
  value: 'https://example.com',
  size: 1000,

  style: QRStyle.SQUARE,
  fgColor: '#000000',
  gradientType: GradientType.NONE,
  fgColorEnd: '#4f46e5',

  bgEnabled: true,
  bgColor: '#ffffff',

  cornerSquareStyle: CornerSquareStyle.SQUARE,
  cornerSquareColor: null,

  cornerDotStyle: CornerDotStyle.SQUARE,
  cornerDotColor: null,

  logoUrl: null,
  logoSize: 0.2,
};

import React, { useState, useEffect } from 'react';
import { 
  QRCodeConfig, QRStyle, CornerSquareStyle, CornerDotStyle, GradientType, QRType 
} from '../types';
import { ColorPicker } from './ColorPicker';
import { generateCreativeContent } from '../services/geminiService';
import { 
  Globe, FileText, Link, UserSquare2, Briefcase, Video, Image, 
  Facebook, Instagram, Share2, MessageCircle, Headphones, 
  Utensils, Smartphone, TicketPercent, Wifi, LayoutGrid, Image as ImageIcon,
  ChevronRight, ChevronDown, Sparkles
} from 'lucide-react';

interface Props {
  config: QRCodeConfig;
  setConfig: React.Dispatch<React.SetStateAction<QRCodeConfig>>;
  onDownload: (format: 'png' | 'jpeg') => void;
}

const SECTION_TITLE = "text-lg font-bold text-slate-800 mb-4";
const SUB_LABEL = "text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3";

export default function Sidebar({ config, setConfig, onDownload }: Props) {
  const [openSections, setOpenSections] = useState({
    pattern: true,
    corners: true,
    logo: false,
    frame: false
  });

  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  // Form states for complex types
  const [wifiState, setWifiState] = useState({ ssid: '', password: '', encryption: 'WPA' });
  const [vcardState, setVcardState] = useState({ firstName: '', lastName: '', phone: '', email: '', org: '', title: '' });
  const [whatsappState, setWhatsappState] = useState({ phone: '', message: '' });
  const [couponState, setCouponState] = useState({ code: '', sale: '' });

  const toggleSection = (key: keyof typeof openSections) => {
    setOpenSections(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleAiGenerate = async () => {
     if (!aiPrompt) return;
     setIsGenerating(true);
     try {
       const text = await generateCreativeContent(aiPrompt);
       setConfig(p => ({...p, value: text}));
     } catch (e) {
       console.error(e);
     } finally {
       setIsGenerating(false);
     }
  };

  // 16 Grid Items configuration
  const types = [
    { id: QRType.WEBSITE, icon: Globe, label: 'Website', color: 'text-blue-500' },
    { id: QRType.PDF, icon: FileText, label: 'PDF', color: 'text-red-500' },
    { id: QRType.LIST_LINKS, icon: Link, label: 'List of Links', color: 'text-cyan-500' },
    { id: QRType.VCARD, icon: UserSquare2, label: 'vCard', color: 'text-emerald-500' },
    { id: QRType.BUSINESS, icon: Briefcase, label: 'Business', color: 'text-slate-600' },
    { id: QRType.VIDEO, icon: Video, label: 'Video', color: 'text-pink-500' },
    { id: QRType.IMAGES, icon: Image, label: 'Images', color: 'text-purple-500' },
    { id: QRType.FACEBOOK, icon: Facebook, label: 'Facebook', color: 'text-blue-700' },
    { id: QRType.INSTAGRAM, icon: Instagram, label: 'Instagram', color: 'text-pink-600' },
    { id: QRType.SOCIAL_MEDIA, icon: Share2, label: 'Social Media', color: 'text-orange-500' },
    { id: QRType.WHATSAPP, icon: MessageCircle, label: 'WhatsApp', color: 'text-green-500' },
    { id: QRType.MP3, icon: Headphones, label: 'MP3', color: 'text-indigo-500' },
    { id: QRType.MENU, icon: Utensils, label: 'Menu', color: 'text-yellow-600' },
    { id: QRType.APPS, icon: Smartphone, label: 'Apps', color: 'text-zinc-600' },
    { id: QRType.COUPON, icon: TicketPercent, label: 'Coupon', color: 'text-rose-500' },
    { id: QRType.WIFI, icon: Wifi, label: 'WiFi', color: 'text-sky-500' },
  ];

  // Effect to update config.value when complex form states change
  useEffect(() => {
    if (config.type === QRType.WIFI) {
      setConfig(c => ({...c, value: `WIFI:S:${wifiState.ssid};T:${wifiState.encryption};P:${wifiState.password};;`}));
    } else if (config.type === QRType.VCARD) {
      const vcard = `BEGIN:VCARD\nVERSION:3.0\nN:${vcardState.lastName};${vcardState.firstName}\nFN:${vcardState.firstName} ${vcardState.lastName}\nORG:${vcardState.org}\nTITLE:${vcardState.title}\nTEL:${vcardState.phone}\nEMAIL:${vcardState.email}\nEND:VCARD`;
      setConfig(c => ({...c, value: vcard}));
    } else if (config.type === QRType.WHATSAPP) {
      setConfig(c => ({...c, value: `https://wa.me/${whatsappState.phone}?text=${encodeURIComponent(whatsappState.message)}`}));
    } else if (config.type === QRType.COUPON) {
      setConfig(c => ({...c, value: `Coupon: ${couponState.code} - ${couponState.sale}`}));
    }
  }, [wifiState, vcardState, whatsappState, couponState, config.type, setConfig]);

  const renderContentForm = () => {
    switch(config.type) {
      case QRType.WIFI:
        return (
          <div className="space-y-3">
             <input placeholder="Network Name (SSID)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={wifiState.ssid} onChange={e => setWifiState({...wifiState, ssid: e.target.value})} />
             <input placeholder="Password" type="password" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={wifiState.password} onChange={e => setWifiState({...wifiState, password: e.target.value})} />
             <select className="w-full p-3 border rounded-lg text-sm outline-none bg-white"
               value={wifiState.encryption} onChange={e => setWifiState({...wifiState, encryption: e.target.value})}>
               <option value="WPA">WPA/WPA2</option>
               <option value="WEP">WEP</option>
               <option value="nopass">No Encryption</option>
             </select>
          </div>
        );
      case QRType.VCARD:
        return (
          <div className="space-y-3">
             <div className="flex gap-2">
               <input placeholder="First Name" className="flex-1 p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
                 value={vcardState.firstName} onChange={e => setVcardState({...vcardState, firstName: e.target.value})} />
               <input placeholder="Last Name" className="flex-1 p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
                 value={vcardState.lastName} onChange={e => setVcardState({...vcardState, lastName: e.target.value})} />
             </div>
             <input placeholder="Phone Number" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.phone} onChange={e => setVcardState({...vcardState, phone: e.target.value})} />
             <input placeholder="Email" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.email} onChange={e => setVcardState({...vcardState, email: e.target.value})} />
             <input placeholder="Company" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.org} onChange={e => setVcardState({...vcardState, org: e.target.value})} />
             <input placeholder="Job Title" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.title} onChange={e => setVcardState({...vcardState, title: e.target.value})} />
          </div>
        );
      case QRType.WHATSAPP:
        return (
          <div className="space-y-3">
            <input placeholder="WhatsApp Number (e.g. 15550001234)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={whatsappState.phone} onChange={e => setWhatsappState({...whatsappState, phone: e.target.value})} />
             <textarea placeholder="Pre-filled Message" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500 h-24"
               value={whatsappState.message} onChange={e => setWhatsappState({...whatsappState, message: e.target.value})} />
          </div>
        );
      case QRType.COUPON:
        return (
          <div className="space-y-3">
             <input placeholder="Coupon Code (e.g. SUMMER20)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={couponState.code} onChange={e => setCouponState({...couponState, code: e.target.value})} />
             <input placeholder="Discount Details (e.g. 20% OFF)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={couponState.sale} onChange={e => setCouponState({...couponState, sale: e.target.value})} />
          </div>
        );
      default:
        // Generic Input for URL/Text based types
        let placeholder = "https://example.com";
        let label = "Website URL";

        if (config.type === QRType.PDF) { placeholder = "Paste PDF URL or link"; label = "PDF Link"; }
        if (config.type === QRType.VIDEO) { placeholder = "https://youtube.com/watch?v=..."; label = "Video URL"; }
        if (config.type === QRType.FACEBOOK) { placeholder = "https://facebook.com/yourpage"; label = "Facebook URL"; }
        if (config.type === QRType.INSTAGRAM) { placeholder = "https://instagram.com/yourusername"; label = "Instagram URL"; }
        if (config.type === QRType.MP3) { placeholder = "https://soundcloud.com/..."; label = "Audio Link"; }

        return (
          <div className="space-y-3">
             <label className="block text-sm font-semibold text-slate-700">{label} *</label>
             <div className="flex gap-2">
               <input 
                 type="text" 
                 value={config.value}
                 onChange={(e) => setConfig({...config, value: e.target.value})}
                 className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none text-sm"
                 placeholder={placeholder}
               />
             </div>

             {/* Simple Fake Upload Button for File types to mimic functionality */}
             {['pdf', 'images', 'mp3', 'video', 'menu'].includes(config.type) && (
               <div className="p-4 border-2 border-dashed border-slate-200 rounded-xl text-center hover:bg-slate-50 cursor-pointer">
                  <p className="text-sm text-slate-500 font-medium">Click to upload file</p>
                  <p className="text-xs text-slate-400 mt-1">(Simulated)</p>
               </div>
             )}

             {config.type === QRType.TEXT && (
                <div className="mt-3 flex gap-2">
                   <input 
                     value={aiPrompt}
                     onChange={(e) => setAiPrompt(e.target.value)}
                     placeholder="Generate with AI..."
                     className="flex-1 text-xs p-2 border rounded"
                   />
                   <button onClick={handleAiGenerate} className="bg-blue-600 text-white text-xs px-3 rounded flex items-center gap-1">
                      <Sparkles size={12} /> Gen
                   </button>
                </div>
             )}
          </div>
        );
    }
  };

  const StyleCard = ({ active, children, onClick }: { active: boolean, children: React.ReactNode, onClick: () => void }) => (
    <div 
      onClick={onClick}
      className={`
        aspect-square rounded-xl border-2 flex items-center justify-center cursor-pointer transition-all
        ${active ? 'border-blue-500 bg-blue-50 text-blue-600' : 'border-slate-100 bg-white hover:border-slate-200 text-slate-400'}
      `}
    >
      {children}
    </div>
  );

  return (
    <div className="h-full bg-white flex flex-col font-sans">
      <div className="flex-1 overflow-y-auto custom-scrollbar">
        <div className="p-6 space-y-10">

          {/* SECTION 1: Type Selection */}
          <section>
            <h2 className={SECTION_TITLE}>1. Select a type of QR code</h2>
            <div className="grid grid-cols-4 gap-3">
              {types.map((t) => (
                <button
                  key={t.id}
                  onClick={() => setConfig({ ...config, type: t.id })}
                  className={`
                    flex flex-col items-center justify-center p-2 rounded-xl border transition-all h-24
                    ${config.type === t.id 
                      ? 'border-blue-500 bg-blue-50 text-blue-600 shadow-sm ring-1 ring-blue-500' 
                      : 'border-slate-100 hover:border-blue-200 text-slate-500 hover:bg-slate-50'}
                  `}
                >
                  <div className={`mb-2 ${config.type === t.id ? 'text-blue-600' : t.color}`}>
                    <t.icon size={24} />
                  </div>
                  <span className="text-[10px] font-semibold text-center leading-tight">{t.label}</span>
                </button>
              ))}
            </div>
          </section>

          {/* SECTION 2: Content */}
          <section>
            <h2 className={SECTION_TITLE}>2. Add content</h2>
            <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100">
               {renderContentForm()}
            </div>
          </section>

          {/* SECTION 3: Design */}
          <section>
             <h2 className={SECTION_TITLE}>3. Design the QR</h2>

             <div className="space-y-4">

                {/* 3.1 Pattern */}
                <div className="border border-slate-100 rounded-2xl overflow-hidden shadow-sm">
                   <button 
                     onClick={() => toggleSection('pattern')}
                     className="w-full flex items-center justify-between p-4 bg-white hover:bg-slate-50 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><LayoutGrid size={20}/></div>
                         <span className="font-semibold text-slate-700">QR Code Pattern</span>
                      </div>
                      {openSections.pattern ? <ChevronDown size={20} className="text-slate-400"/> : <ChevronRight size={20} className="text-slate-400"/>}
                   </button>

                   {openSections.pattern && (
                     <div className="p-4 bg-white border-t border-slate-50 space-y-6">
                        <div>
                           <div className={SUB_LABEL}>Pattern Style</div>
                           <div className="grid grid-cols-5 gap-3">
                              {[QRStyle.SQUARE, QRStyle.ROUNDED, QRStyle.DOTS, QRStyle.DIAMOND, QRStyle.HEART].map(style => (
                                <StyleCard 
                                  key={style} 
                                  active={config.style === style}
                                  onClick={() => setConfig({...config, style})}
                                >
                                   <div className={`w-4 h-4 bg-current ${style === QRStyle.ROUNDED ? 'rounded-sm' : style === QRStyle.DOTS ? 'rounded-full' : style === QRStyle.DIAMOND ? 'rotate-45' : ''}`} />
                                </StyleCard>
                              ))}
                           </div>
                        </div>

                        <div>
                           <div className="flex items-center justify-between mb-2">
                             <div className={SUB_LABEL}>Pattern Color</div>
                             <div className="flex items-center gap-2">
                               <span className="text-xs text-slate-500">Gradient</span>
                               <button 
                                 onClick={() => setConfig({...config, gradientType: config.gradientType === GradientType.NONE ? GradientType.RADIAL : GradientType.NONE})}
                                 className={`w-10 h-5 rounded-full p-0.5 transition-colors ${config.gradientType !== GradientType.NONE ? 'bg-blue-500' : 'bg-slate-200'}`}
                               >
                                 <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${config.gradientType !== GradientType.NONE ? 'translate-x-5' : ''}`} />
                               </button>
                             </div>
                           </div>

                           <div className="flex gap-4">
                              <div className="flex-1">
                                <ColorPicker label="Color 1" color={config.fgColor} onChange={(c) => setConfig({...config, fgColor: c})} />
                              </div>
                              {config.gradientType !== GradientType.NONE && (
                                <div className="flex-1">
                                  <ColorPicker label="Color 2" color={config.fgColorEnd} onChange={(c) => setConfig({...config, fgColorEnd: c})} />
                                </div>
                              )}
                           </div>

                           {config.gradientType !== GradientType.NONE && (
                              <select 
                                value={config.gradientType}
                                onChange={(e) => setConfig({...config, gradientType: e.target.value as GradientType})}
                                className="mt-3 w-full p-2 text-xs border rounded bg-slate-50 outline-none"
                              >
                                 <option value={GradientType.RADIAL}>Radial</option>
                                 <option value={GradientType.LINEAR_VERTICAL}>Vertical</option>
                                 <option value={GradientType.LINEAR_HORIZONTAL}>Horizontal</option>
                              </select>
                           )}
                        </div>

                        <div>
                           <div className="flex items-center justify-between mb-2">
                              <div className={SUB_LABEL}>Background Color</div>
                              <input 
                                type="checkbox" 
                                checked={config.bgEnabled} 
                                onChange={(e) => setConfig({...config, bgEnabled: e.target.checked})}
                                className="accent-blue-500"
                              />
                           </div>
                           {config.bgEnabled && (
                             <ColorPicker label="Background" color={config.bgColor} onChange={(c) => setConfig({...config, bgColor: c})} />
                           )}
                        </div>
                     </div>
                   )}
                </div>

                {/* 3.2 Corners */}
                <div className="border border-slate-100 rounded-2xl overflow-hidden shadow-sm">
                   <button 
                     onClick={() => toggleSection('corners')}
                     className="w-full flex items-center justify-between p-4 bg-white hover:bg-slate-50 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><LayoutGrid size={20}/></div>
                         <span className="font-semibold text-slate-700">QR Code Corners</span>
                      </div>
                      {openSections.corners ? <ChevronDown size={20} className="text-slate-400"/> : <ChevronRight size={20} className="text-slate-400"/>}
                   </button>

                   {openSections.corners && (
                     <div className="p-4 bg-white border-t border-slate-50 space-y-6">
                        <div className="grid grid-cols-2 gap-6">
                           <div>
                              <div className={SUB_LABEL}>Corner Shape</div>
                              <div className="grid grid-cols-3 gap-2">
                                 {[CornerSquareStyle.SQUARE, CornerSquareStyle.DOT, CornerSquareStyle.EXTRA_ROUNDED].map(s => (
                                    <StyleCard 
                                      key={s} 
                                      active={config.cornerSquareStyle === s}
                                      onClick={() => setConfig({...config, cornerSquareStyle: s})}
                                    >
                                       <div className={`w-5 h-5 border-2 border-current ${s === CornerSquareStyle.DOT ? 'rounded-full' : s === CornerSquareStyle.EXTRA_ROUNDED ? 'rounded-lg' : ''}`} />
                                    </StyleCard>
                                 ))}
                              </div>
                              <div className="mt-3">
                                 <ColorPicker 
                                    label="Frame Color" 
                                    color={config.cornerSquareColor || config.fgColor} 
                                    onChange={(c) => setConfig({...config, cornerSquareColor: c})} 
                                 />
                              </div>
                           </div>

                           <div>
                              <div className={SUB_LABEL}>Corner Dot</div>
                              <div className="grid grid-cols-3 gap-2">
                                 {[CornerDotStyle.SQUARE, CornerDotStyle.DOT, CornerDotStyle.DIAMOND].map(s => (
                                    <StyleCard 
                                      key={s} 
                                      active={config.cornerDotStyle === s}
                                      onClick={() => setConfig({...config, cornerDotStyle: s})}
                                    >
                                       <div className={`w-2.5 h-2.5 bg-current ${s === CornerDotStyle.DOT ? 'rounded-full' : s === CornerDotStyle.DIAMOND ? 'rotate-45' : ''}`} />
                                    </StyleCard>
                                 ))}
                              </div>
                              <div className="mt-3">
                                 <ColorPicker 
                                    label="Dot Color" 
                                    color={config.cornerDotColor || config.fgColor} 
                                    onChange={(c) => setConfig({...config, cornerDotColor: c})} 
                                 />
                              </div>
                           </div>
                        </div>
                     </div>
                   )}
                </div>

                {/* 3.3 Logo */}
                <div className="border border-slate-100 rounded-2xl overflow-hidden shadow-sm">
                   <button 
                     onClick={() => toggleSection('logo')}
                     className="w-full flex items-center justify-between p-4 bg-white hover:bg-slate-50 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><ImageIcon size={20}/></div>
                         <span className="font-semibold text-slate-700">Add Logo</span>
                      </div>
                      {openSections.logo ? <ChevronDown size={20} className="text-slate-400"/> : <ChevronRight size={20} className="text-slate-400"/>}
                   </button>

                   {openSections.logo && (
                     <div className="p-4 bg-white border-t border-slate-50">
                        <label className="block border-2 border-dashed border-slate-200 rounded-xl p-8 hover:bg-slate-50 transition-colors cursor-pointer text-center">
                           <input type="file" className="hidden" accept="image/*" onChange={(e) => {
                              if (e.target.files?.[0]) {
                                 const r = new FileReader();
                                 r.onload = (ev) => setConfig({...config, logoUrl: ev.target?.result as string});
                                 r.readAsDataURL(e.target.files[0]);
                              }
                           }}/>
                           <div className="flex flex-col items-center gap-2 text-slate-400">
                              <ImageIcon size={32} />
                              <span className="text-sm font-medium">Upload your logo (Max 1MB)</span>
                           </div>
                        </label>

                        {config.logoUrl && (
                           <div className="mt-4 flex items-center gap-4 bg-slate-50 p-3 rounded-lg">
                              <img src={config.logoUrl} className="w-10 h-10 object-contain bg-white rounded shadow-sm p-1" />
                              <button onClick={() => setConfig({...config, logoUrl: null})} className="text-xs text-red-500 font-medium">Remove</button>
                           </div>
                        )}
                     </div>
                   )}
                </div>

             </div>
          </section>

          {/* Download & Size */}
          <section className="pt-6 border-t border-slate-100">
             <div className="mb-4">
               <div className="flex justify-between text-xs text-slate-500 mb-2 font-medium uppercase tracking-wide">
                 <span>Low Quality</span>
                 <span>High Quality</span>
               </div>
               <input 
                  type="range" min="500" max="2000" step="100" 
                  value={config.size} 
                  onChange={(e) => setConfig({...config, size: parseInt(e.target.value)})}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
               />
               <div className="text-center text-xs text-slate-400 mt-1">{config.size} x {config.size} px</div>
             </div>

             <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => onDownload('png')} 
                  className="bg-blue-600 text-white py-3 rounded-xl font-bold text-sm hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200"
                >
                   Download PNG
                </button>
                <button 
                   onClick={() => onDownload('jpeg')} 
                   className="bg-white border border-slate-200 text-slate-700 py-3 rounded-xl font-bold text-sm hover:bg-slate-50 transition-colors"
                >
                   Download JPG
                </button>
             </div>
          </section>

        </div>
      </div>
    </div>
  );
}

export enum QRType {
  WEBSITE = 'website',
  PDF = 'pdf',
  LIST_LINKS = 'list_links',
  VCARD = 'vcard',
  BUSINESS = 'business',
  VIDEO = 'video',
  IMAGES = 'images',
  FACEBOOK = 'facebook',
  INSTAGRAM = 'instagram',
  SOCIAL_MEDIA = 'social_media',
  WHATSAPP = 'whatsapp',
  MP3 = 'mp3',
  MENU = 'menu',
  APPS = 'apps',
  COUPON = 'coupon',
  WIFI = 'wifi',
  TEXT = 'text'
}

export enum QRStyle {
  SQUARE = 'square',
  ROUNDED = 'rounded', // "Round"
  EXTRA_ROUNDED = 'extra_rounded', // "Extra R"
  DOTS = 'dots',
  CLASSY = 'classy', // "Classy"
  CLASSY_R = 'classy_r', // "Classy R"
  DIAMOND = 'diamond',
  HEART = 'heart',
}

export enum CornerSquareStyle {
  SQUARE = 'square',
  DOT = 'dot', // Circle
  EXTRA_ROUNDED = 'extra_rounded',
}

export enum CornerDotStyle {
  SQUARE = 'square',
  DOT = 'dot',
  DIAMOND = 'diamond',
}

export enum GradientType {
  NONE = 'none',
  LINEAR_VERTICAL = 'linear_vertical',
  LINEAR_HORIZONTAL = 'linear_horizontal',
  RADIAL = 'radial',
}

export interface QRCodeConfig {
  type: QRType;
  value: string;
  size: number;

  // Pattern (Body)
  style: QRStyle;
  fgColor: string;
  gradientType: GradientType;
  fgColorEnd: string; // Used if gradient is active

  // Background
  bgEnabled: boolean;
  bgColor: string;

  // Corners (Eyes)
  cornerSquareStyle: CornerSquareStyle;
  cornerSquareColor: string | null; // null = use fgColor

  cornerDotStyle: CornerDotStyle;
  cornerDotColor: string | null; // null = use fgColor

  // Logo
  logoUrl: string | null;
  logoSize: number;
}

export const DEFAULT_CONFIG: QRCodeConfig = {
  type: QRType.WEBSITE,
  value: 'https://example.com',
  size: 1000,

  style: QRStyle.SQUARE,
  fgColor: '#000000',
  gradientType: GradientType.NONE,
  fgColorEnd: '#4f46e5',

  bgEnabled: true,
  bgColor: '#ffffff',

  cornerSquareStyle: CornerSquareStyle.SQUARE,
  cornerSquareColor: null,

  cornerDotStyle: CornerDotStyle.SQUARE,
  cornerDotColor: null,

  logoUrl: null,
  logoSize: 0.2,
};

import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import QRCode from 'qrcode';
import { QRCodeConfig, QRStyle, CornerSquareStyle, CornerDotStyle, GradientType } from '../types';

interface Props {
  config: QRCodeConfig;
  className?: string;
}

export interface QRCodeHandle {
  download: (format: 'png' | 'jpeg') => void;
}

const QRCodeRenderer = forwardRef<QRCodeHandle, Props>(({ config, className }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useImperativeHandle(ref, () => ({
    download: (format) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const link = document.createElement('a');
      link.download = `qrcode-${Date.now()}.${format}`;
      link.href = canvas.toDataURL(`image/${format}`, 1.0);
      link.click();
    }
  }));

  useEffect(() => {
    const renderQR = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // 1. Generate Matrix
      let qrData;
      try {
        qrData = QRCode.create(config.value || ' ', {
          errorCorrectionLevel: 'H',
          margin: 0 
        });
      } catch (e) {
        return;
      }

      const moduleCount = qrData.modules.size;
      const size = config.size;
      const margin = config.bgEnabled ? 2 * (size / moduleCount) : 0; // Small quiet zone
      const drawingSize = size - (margin * 2);
      const cellSize = drawingSize / moduleCount;

      canvas.width = size;
      canvas.height = size;
      ctx.clearRect(0, 0, size, size);

      // 2. Draw Background
      if (config.bgEnabled) {
        ctx.fillStyle = config.bgColor;
        ctx.fillRect(0, 0, size, size);
      }

      // Helper: Gradients
      const createGradient = (startColor: string, endColor: string, type: GradientType) => {
        if (type === GradientType.NONE) return startColor;
        let grad;
        if (type === GradientType.LINEAR_VERTICAL) {
          grad = ctx.createLinearGradient(0, margin, 0, size - margin);
        } else if (type === GradientType.LINEAR_HORIZONTAL) {
          grad = ctx.createLinearGradient(margin, 0, size - margin, 0);
        } else { // RADIAL
          const c = size / 2;
          grad = ctx.createRadialGradient(c, c, 0, c, c, size / 1.5);
        }
        grad.addColorStop(0, startColor);
        grad.addColorStop(1, endColor);
        return grad;
      };

      const patternFill = createGradient(config.fgColor, config.fgColorEnd, config.gradientType);

      // 3. Identification Patterns (Eyes)
      const isEye = (r: number, c: number) => {
        // Top-Left
        if (r < 7 && c < 7) return true;
        // Top-Right
        if (r < 7 && c >= moduleCount - 7) return true;
        // Bottom-Left
        if (r >= moduleCount - 7 && c < 7) return true;
        return false;
      };

      const isEyeFrame = (r: number, c: number) => {
        if (!isEye(r, c)) return false;
        // Borders of the 7x7 box
        if ((r === 0 || r === 6) && c >= 0 && c <= 6) return true; // TL Horizontal
        if ((c === 0 || c === 6) && r >= 0 && r <= 6) return true; // TL Vertical

        if ((r === 0 || r === 6) && c >= moduleCount - 7) return true; // TR Horizontal
        if ((c === moduleCount - 7 || c === moduleCount - 1) && r <= 6) return true; // TR Vertical

        if ((r === moduleCount - 7 || r === moduleCount - 1) && c <= 6) return true; // BL Horizontal
        if ((c === 0 || c === 6) && r >= moduleCount - 7) return true; // BL Vertical
        return false;
      };

      const isEyeDot = (r: number, c: number) => {
         if (!isEye(r, c)) return false;
         // Center 3x3 block relative to eye
         const check = (rBase: number, cBase: number) => {
            return r >= rBase + 2 && r <= rBase + 4 && c >= cBase + 2 && c <= cBase + 4;
         }
         if (check(0, 0)) return true; // TL
         if (check(0, moduleCount - 7)) return true; // TR
         if (check(moduleCount - 7, 0)) return true; // BL
         return false;
      };

      // Helper: Draw Shape
      const drawModule = (cx: number, cy: number, w: number, style: QRStyle | CornerSquareStyle | CornerDotStyle) => {
         const radius = w * 0.35;

         ctx.beginPath();
         switch (style) {
            case QRStyle.DOTS:
            case CornerSquareStyle.DOT:
            case CornerDotStyle.DOT:
               ctx.arc(cx + w/2, cy + w/2, w/2 * 0.85, 0, Math.PI * 2);
               ctx.fill();
               break;

            case QRStyle.ROUNDED: // Standard Round (Square with moderate radius)
            case CornerSquareStyle.EXTRA_ROUNDED:
               ctx.roundRect(cx, cy, w, w, w * 0.25);
               ctx.fill();
               break;

            case QRStyle.EXTRA_ROUNDED: // Extra Round (Max radius)
               ctx.roundRect(cx, cy, w, w, w * 0.5);
               ctx.fill();
               break;

            case QRStyle.CLASSY: // Round Top-Left & Bottom-Right
               // [tl, tr, br, bl]
               ctx.roundRect(cx, cy, w, w, [w * 0.5, 0, w * 0.5, 0]);
               ctx.fill();
               break;

            case QRStyle.CLASSY_R: // Round Top-Right & Bottom-Left
               ctx.roundRect(cx, cy, w, w, [0, w * 0.5, 0, w * 0.5]);
               ctx.fill();
               break;

            case QRStyle.DIAMOND:
            case CornerDotStyle.DIAMOND:
               ctx.moveTo(cx + w/2, cy);
               ctx.lineTo(cx + w, cy + w/2);
               ctx.lineTo(cx + w/2, cy + w);
               ctx.lineTo(cx, cy + w/2);
               ctx.fill();
               break;

            case QRStyle.HEART:
               // Simple Heart Shape
               const hw = w * 0.9;
               const hx = cx + (w - hw)/2;
               const hy = cy + (w - hw)/2;
               const topCurveHeight = hw * 0.3;
               ctx.moveTo(hx + hw / 2, hy + hw / 5);
               ctx.bezierCurveTo(hx + hw / 2, hy, hx, hy, hx, hy + topCurveHeight);
               ctx.bezierCurveTo(hx, hy + (hw + topCurveHeight) / 2, hx + hw / 2, hy + (hw + topCurveHeight) / 2, hx + hw / 2, hy + hw);
               ctx.bezierCurveTo(hx + hw / 2, hy + (hw + topCurveHeight) / 2, hx + hw, hy + (hw + topCurveHeight) / 2, hx + hw, hy + topCurveHeight);
               ctx.bezierCurveTo(hx + hw, hy, hx + hw / 2, hy, hx + hw / 2, hy + hw / 5);
               ctx.fill();
               break;

            default: // SQUARE
               // Slightly overlap to avoid sub-pixel gaps
               const overlap = style === QRStyle.SQUARE ? 0.3 : 0;
               ctx.rect(cx, cy, w + overlap, w + overlap);
               ctx.fill();
         }
      };

      const modules = qrData.modules.data;

      for (let r = 0; r < moduleCount; r++) {
        for (let c = 0; c < moduleCount; c++) {
           const idx = r * moduleCount + c;
           if (!modules[idx]) continue;

           const x = margin + c * cellSize;
           const y = margin + r * cellSize;

           if (isEye(r, c)) {
             // It's an eye part
             if (isEyeFrame(r, c)) {
                ctx.fillStyle = config.cornerSquareColor || config.fgColor;
                drawModule(x, y, cellSize, config.cornerSquareStyle);
             } else if (isEyeDot(r, c)) {
                ctx.fillStyle = config.cornerDotColor || config.fgColor;
                drawModule(x, y, cellSize, config.cornerDotStyle);
             }
           } else {
             // Regular Pattern
             ctx.fillStyle = patternFill;
             drawModule(x, y, cellSize, config.style);
           }
        }
      }

      // 4. Logo
      if (config.logoUrl) {
        const logoImg = new Image();
        logoImg.crossOrigin = "Anonymous";
        logoImg.src = config.logoUrl;

        await new Promise((resolve) => {
          logoImg.onload = resolve;
          logoImg.onerror = resolve; 
        });

        const logoSizePx = size * config.logoSize;
        const logoX = (size - logoSizePx) / 2;
        const logoY = (size - logoSizePx) / 2;

        if (config.bgEnabled) {
           ctx.fillStyle = config.bgColor;
           ctx.beginPath();
           // White backing for logo
           ctx.roundRect(logoX - 5, logoY - 5, logoSizePx + 10, logoSizePx + 10, 10);
           ctx.fill();
        }
        ctx.drawImage(logoImg, logoX, logoY, logoSizePx, logoSizePx);
      }
    };

    renderQR();
  }, [config]);

  return (
    <canvas 
      ref={canvasRef} 
      className={className}
      style={{ display: 'block' }}
    />
  );
});

QRCodeRenderer.displayName = "QRCodeRenderer";
export default QRCodeRenderer;

import React, { useState, useEffect } from 'react';
import { 
  QRCodeConfig, QRStyle, CornerSquareStyle, CornerDotStyle, GradientType, QRType 
} from '../types';
import { ColorPicker } from './ColorPicker';
import { generateCreativeContent } from '../services/geminiService';
import { 
  Globe, FileText, Link, UserSquare2, Briefcase, Video, Image, 
  Facebook, Instagram, Share2, MessageCircle, Headphones, 
  Utensils, Smartphone, TicketPercent, Wifi, LayoutGrid, Image as ImageIcon,
  ChevronRight, ChevronDown, Sparkles
} from 'lucide-react';

interface Props {
  config: QRCodeConfig;
  setConfig: React.Dispatch<React.SetStateAction<QRCodeConfig>>;
  onDownload: (format: 'png' | 'jpeg') => void;
}

const SECTION_TITLE = "text-lg font-bold text-slate-800 mb-4";
const SUB_LABEL = "text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3";

export default function Sidebar({ config, setConfig, onDownload }: Props) {
  const [openSections, setOpenSections] = useState({
    pattern: true,
    corners: true,
    logo: false,
    frame: false
  });

  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  // Form states for complex types
  const [wifiState, setWifiState] = useState({ ssid: '', password: '', encryption: 'WPA' });
  const [vcardState, setVcardState] = useState({ firstName: '', lastName: '', phone: '', email: '', org: '', title: '' });
  const [whatsappState, setWhatsappState] = useState({ phone: '', message: '' });
  const [couponState, setCouponState] = useState({ code: '', sale: '' });

  const toggleSection = (key: keyof typeof openSections) => {
    setOpenSections(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleAiGenerate = async () => {
     if (!aiPrompt) return;
     setIsGenerating(true);
     try {
       const text = await generateCreativeContent(aiPrompt);
       setConfig(p => ({...p, value: text}));
     } catch (e) {
       console.error(e);
     } finally {
       setIsGenerating(false);
     }
  };

  // 16 Grid Items configuration
  const types = [
    { id: QRType.WEBSITE, icon: Globe, label: 'Website', color: 'text-blue-500' },
    { id: QRType.PDF, icon: FileText, label: 'PDF', color: 'text-red-500' },
    { id: QRType.LIST_LINKS, icon: Link, label: 'List of Links', color: 'text-cyan-500' },
    { id: QRType.VCARD, icon: UserSquare2, label: 'vCard', color: 'text-emerald-500' },
    { id: QRType.BUSINESS, icon: Briefcase, label: 'Business', color: 'text-slate-600' },
    { id: QRType.VIDEO, icon: Video, label: 'Video', color: 'text-pink-500' },
    { id: QRType.IMAGES, icon: Image, label: 'Images', color: 'text-purple-500' },
    { id: QRType.FACEBOOK, icon: Facebook, label: 'Facebook', color: 'text-blue-700' },
    { id: QRType.INSTAGRAM, icon: Instagram, label: 'Instagram', color: 'text-pink-600' },
    { id: QRType.SOCIAL_MEDIA, icon: Share2, label: 'Social Media', color: 'text-orange-500' },
    { id: QRType.WHATSAPP, icon: MessageCircle, label: 'WhatsApp', color: 'text-green-500' },
    { id: QRType.MP3, icon: Headphones, label: 'MP3', color: 'text-indigo-500' },
    { id: QRType.MENU, icon: Utensils, label: 'Menu', color: 'text-yellow-600' },
    { id: QRType.APPS, icon: Smartphone, label: 'Apps', color: 'text-zinc-600' },
    { id: QRType.COUPON, icon: TicketPercent, label: 'Coupon', color: 'text-rose-500' },
    { id: QRType.WIFI, icon: Wifi, label: 'WiFi', color: 'text-sky-500' },
  ];

  // Effect to update config.value when complex form states change
  useEffect(() => {
    if (config.type === QRType.WIFI) {
      setConfig(c => ({...c, value: `WIFI:S:${wifiState.ssid};T:${wifiState.encryption};P:${wifiState.password};;`}));
    } else if (config.type === QRType.VCARD) {
      const vcard = `BEGIN:VCARD\nVERSION:3.0\nN:${vcardState.lastName};${vcardState.firstName}\nFN:${vcardState.firstName} ${vcardState.lastName}\nORG:${vcardState.org}\nTITLE:${vcardState.title}\nTEL:${vcardState.phone}\nEMAIL:${vcardState.email}\nEND:VCARD`;
      setConfig(c => ({...c, value: vcard}));
    } else if (config.type === QRType.WHATSAPP) {
      setConfig(c => ({...c, value: `https://wa.me/${whatsappState.phone}?text=${encodeURIComponent(whatsappState.message)}`}));
    } else if (config.type === QRType.COUPON) {
      setConfig(c => ({...c, value: `Coupon: ${couponState.code} - ${couponState.sale}`}));
    }
  }, [wifiState, vcardState, whatsappState, couponState, config.type, setConfig]);

  const renderContentForm = () => {
    switch(config.type) {
      case QRType.WIFI:
        return (
          <div className="space-y-3">
             <input placeholder="Network Name (SSID)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={wifiState.ssid} onChange={e => setWifiState({...wifiState, ssid: e.target.value})} />
             <input placeholder="Password" type="password" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={wifiState.password} onChange={e => setWifiState({...wifiState, password: e.target.value})} />
             <select className="w-full p-3 border rounded-lg text-sm outline-none bg-white"
               value={wifiState.encryption} onChange={e => setWifiState({...wifiState, encryption: e.target.value})}>
               <option value="WPA">WPA/WPA2</option>
               <option value="WEP">WEP</option>
               <option value="nopass">No Encryption</option>
             </select>
          </div>
        );
      case QRType.VCARD:
        return (
          <div className="space-y-3">
             <div className="flex gap-2">
               <input placeholder="First Name" className="flex-1 p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
                 value={vcardState.firstName} onChange={e => setVcardState({...vcardState, firstName: e.target.value})} />
               <input placeholder="Last Name" className="flex-1 p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
                 value={vcardState.lastName} onChange={e => setVcardState({...vcardState, lastName: e.target.value})} />
             </div>
             <input placeholder="Phone Number" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.phone} onChange={e => setVcardState({...vcardState, phone: e.target.value})} />
             <input placeholder="Email" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.email} onChange={e => setVcardState({...vcardState, email: e.target.value})} />
             <input placeholder="Company" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.org} onChange={e => setVcardState({...vcardState, org: e.target.value})} />
             <input placeholder="Job Title" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={vcardState.title} onChange={e => setVcardState({...vcardState, title: e.target.value})} />
          </div>
        );
      case QRType.WHATSAPP:
        return (
          <div className="space-y-3">
            <input placeholder="WhatsApp Number (e.g. 15550001234)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={whatsappState.phone} onChange={e => setWhatsappState({...whatsappState, phone: e.target.value})} />
             <textarea placeholder="Pre-filled Message" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500 h-24"
               value={whatsappState.message} onChange={e => setWhatsappState({...whatsappState, message: e.target.value})} />
          </div>
        );
      case QRType.COUPON:
        return (
          <div className="space-y-3">
             <input placeholder="Coupon Code (e.g. SUMMER20)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={couponState.code} onChange={e => setCouponState({...couponState, code: e.target.value})} />
             <input placeholder="Discount Details (e.g. 20% OFF)" className="w-full p-3 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
               value={couponState.sale} onChange={e => setCouponState({...couponState, sale: e.target.value})} />
          </div>
        );
      default:
        // Generic Input for URL/Text based types
        let placeholder = "https://example.com";
        let label = "Website URL";

        if (config.type === QRType.PDF) { placeholder = "Paste PDF URL or link"; label = "PDF Link"; }
        if (config.type === QRType.VIDEO) { placeholder = "https://youtube.com/watch?v=..."; label = "Video URL"; }
        if (config.type === QRType.FACEBOOK) { placeholder = "https://facebook.com/yourpage"; label = "Facebook URL"; }
        if (config.type === QRType.INSTAGRAM) { placeholder = "https://instagram.com/yourusername"; label = "Instagram URL"; }
        if (config.type === QRType.MP3) { placeholder = "https://soundcloud.com/..."; label = "Audio Link"; }

        return (
          <div className="space-y-3">
             <label className="block text-sm font-semibold text-slate-700">{label} *</label>
             <div className="flex gap-2">
               <input 
                 type="text" 
                 value={config.value}
                 onChange={(e) => setConfig({...config, value: e.target.value})}
                 className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none text-sm"
                 placeholder={placeholder}
               />
             </div>

             {/* Simple Fake Upload Button for File types to mimic functionality */}
             {['pdf', 'images', 'mp3', 'video', 'menu'].includes(config.type) && (
               <div className="p-4 border-2 border-dashed border-slate-200 rounded-xl text-center hover:bg-slate-50 cursor-pointer">
                  <p className="text-sm text-slate-500 font-medium">Click to upload file</p>
                  <p className="text-xs text-slate-400 mt-1">(Simulated)</p>
               </div>
             )}

             {config.type === QRType.TEXT && (
                <div className="mt-3 flex gap-2">
                   <input 
                     value={aiPrompt}
                     onChange={(e) => setAiPrompt(e.target.value)}
