export enum QRType {
  WEBSITE = 'website',
  PDF = 'pdf',
  LIST_LINKS = 'list_links',
  VCARD = 'vcard',
  BUSINESS = 'business',
  VIDEO = 'video',
  IMAGES = 'images',
  FACEBOOK = 'facebook',
  INSTAGRAM = 'instagram',
  SOCIAL_MEDIA = 'social_media',
  WHATSAPP = 'whatsapp',
  MP3 = 'mp3',
  MENU = 'menu',
  APPS = 'apps',
  COUPON = 'coupon',
  WIFI = 'wifi',
  TEXT = 'text'
}

export type DotType = 'square' | 'dots' | 'rounded' | 'classy' | 'classy-rounded' | 'extra-rounded';
export type CornerType = 'square' | 'dot' | 'extra-rounded';
export type GradientType = 'linear' | 'radial';
export type FileExtension = 'png' | 'jpeg' | 'svg' | 'webp';

export interface GradientConfig {
  type: GradientType;
  rotation: number;
  color1: string;
  color2: string;
}

export interface QRCodeConfig {
  // Content
  type: QRType;
  value: string;

  // Design - Dots
  dotStyle: DotType;
  dotColor: string;
  useGradient: boolean;
  gradient: GradientConfig;

  // Design - Background
  bgEnabled: boolean;
  bgColor: string;

  // Design - Corners
  cornerSquareStyle: CornerType; // 'square' | 'dot' | 'extra-rounded'
  cornerDotStyle: CornerType;    // 'square' | 'dot'

  // Logo
  logoUrl: string | null;

  // Meta
  size: number;
  fileExt: FileExtension;
}

