    type: 'linear',
    rotation: 0,
    color1: '#000000',
    color2: '#2563eb'
  },

  bgEnabled: true,
  bgColor: '#ffffff',

  cornerSquareStyle: 'square',
  cornerDotStyle: 'square',

  logoUrl: null,

  size: 1000,
