};

import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import QRCodeStyling from 'qr-code-styling';
import { QRCodeConfig } from '../types';

interface Props {
  config: QRCodeConfig;
  className?: string;
}

export interface QRCodeHandle {
  download: () => void;
}

const QRCodeRenderer = forwardRef<QRCodeHandle, Props>(({ config, className }, ref) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const qrCode = useRef<QRCodeStyling | null>(null);

  useImperativeHandle(ref, () => ({
    download: async () => {
      if (!qrCode.current) return;
      // Temporarily update size for download if needed, or use current config size
      await qrCode.current.download({ 
        name: `qr-studio-${Date.now()}`, 
        extension: config.fileExt 
      });
    }
  }));

  // Initialize
  useEffect(() => {
    if (!qrCode.current) {
        qrCode.current = new QRCodeStyling({
            width: 300,
            height: 300,
            type: "svg",
            data: config.value,
            image: config.logoUrl || undefined,
            dotsOptions: {
                color: config.dotColor,
                type: config.dotStyle
            },
            backgroundOptions: {
                color: config.bgEnabled ? config.bgColor : 'transparent',
            },
            imageOptions: {
                crossOrigin: "anonymous",
                margin: 5
            }
        });
        if (containerRef.current) {
            containerRef.current.innerHTML = '';
            qrCode.current.append(containerRef.current);
        }
    }
  }, []);

  // Update
  useEffect(() => {
    if (!qrCode.current) return;

    const options: any = {
        width: 300, // Preview size fixed
        height: 300,
        data: config.value,
        image: config.logoUrl || undefined,
        dotsOptions: {
            type: config.dotStyle,
            color: config.dotColor
        },
        backgroundOptions: {
             color: config.bgEnabled ? config.bgColor : 'transparent',
        },
        cornersSquareOptions: {
            type: config.cornerSquareStyle,
            color: config.useGradient ? undefined : config.dotColor // Sync with dots if solid
        },
        cornersDotOptions: {
            type: config.cornerDotStyle,
            color: config.useGradient ? undefined : config.dotColor
        }
    };

    // Apply Gradient
    if (config.useGradient) {
        const gradient = {
            type: config.gradient.type,
            rotation: (config.gradient.rotation * Math.PI) / 180,
            colorStops: [
                { offset: 0, color: config.gradient.color1 },
                { offset: 1, color: config.gradient.color2 }
            ]
        };
        options.dotsOptions.gradient = gradient;
        options.cornersSquareOptions.gradient = gradient;
        options.cornersDotOptions.gradient = gradient;
        // Clear solid colors to ensure gradient shows
        delete options.dotsOptions.color;
        delete options.cornersSquareOptions.color;
        delete options.cornersDotOptions.color;
    }

    // Handle high-res download config (internal state of library)
    // The library uses the width/height passed in update() for the canvas. 
    // When downloading, we want the high res.
    // We update the internal options for download separately, 
    // but for preview we keep it responsive/fixed.
    // Actually qr-code-styling accepts width/height in download() method, 
    // but we can also set the main instance options before download if that fails.
    // For now, we update the preview.

    qrCode.current.update(options);

  }, [config]);

  return (
    <div ref={containerRef} className={className} id="canvas-container"></div>
  );
});

QRCodeRenderer.displayName = "QRCodeRenderer";
export default QRCodeRenderer;

