export default App;

export enum QRType {
  WEBSITE = 'website',
  TEXT = 'text',
  WIFI = 'wifi',
  VCARD = 'vcard',
  PHONE = 'phone',
  LOCATION = 'location',
  CALENDAR = 'calendar',
  BUSINESS = 'business',
  FACEBOOK = 'facebook',
  INSTAGRAM = 'instagram',
  WHATSAPP = 'whatsapp',
  MENU = 'menu'
}

export type DotType = 'square' | 'dots' | 'rounded' | 'classy' | 'classy-rounded' | 'extra-rounded';
export type CornerType = 'square' | 'dot' | 'extra-rounded';
export type GradientType = 'linear' | 'radial';
export type FileExtension = 'png' | 'jpeg' | 'svg' | 'webp';

export interface GradientConfig {
  type: GradientType;
  rotation: number;
  color1: string;
  color2: string;
}

export interface QRCodeConfig {
  // Content
  type: QRType;
  value: string;

  // Design - Dots
  dotStyle: DotType;
  dotColor: string;
  useGradient: boolean;
  gradient: GradientConfig;

  // Design - Background
  bgEnabled: boolean;
  bgColor: string;

  // Design - Corners
  cornerSquareStyle: CornerType; // 'square' | 'dot' | 'extra-rounded'
  cornerDotStyle: CornerType;    // 'square' | 'dot'

  // Logo
  logoUrl: string | null;

  // Meta
  size: number;
  fileExt: FileExtension;
}

