                <div className="h-px bg-slate-100 w-full"></div>

                {/* Patterns */}
                <div>
                     <span className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-3">Pattern Style</span>
                     <div className="grid grid-cols-3 gap-2">
