export enum QRType {
  WEBSITE = 'website',
  TEXT = 'text',
  WIFI = 'wifi',
  VCARD = 'vcard',
  PHONE = 'phone',
  LOCATION = 'location',
  CALENDAR = 'calendar',
  BUSINESS = 'business',
  FACEBOOK = 'facebook',
  INSTAGRAM = 'instagram',
  WHATSAPP = 'whatsapp',
  YOUTUBE = 'youtube'
}

export type DotType = 'square' | 'dots' | 'rounded' | 'classy' | 'classy-rounded' | 'extra-rounded';
export type CornerType = 'square' | 'dot' | 'extra-rounded';
export type GradientType = 'linear' | 'radial';
export type FileExtension = 'png' | 'jpeg' | 'svg' | 'webp';
export type ErrorCorrectionLevel = 'L' | 'M' | 'Q' | 'H';

export interface GradientConfig {
  type: GradientType;
  rotation: number;
  color1: string;
  color2: string;
}

export interface QRCodeConfig {
  // Content
  type: QRType;
  value: string;

  // Design - Dots
  dotStyle: DotType;
  dotColor: string;
  useGradient: boolean;
  gradient: GradientConfig;

  // Design - Background
  bgEnabled: boolean;
  bgColor: string;

  // Design - Corners
  cornerSquareStyle: CornerType; // 'square' | 'dot' | 'extra-rounded'
  cornerDotStyle: CornerType;    // 'square' | 'dot'

  // Configuration
  errorCorrectionLevel: ErrorCorrectionLevel;

  // Logo
  logoUrl: string | null;

  // Meta
  size: number;
  fileExt: FileExtension;
}

export const DEFAULT_CONFIG: QRCodeConfig = {
  type: QRType.WEBSITE,
  value: 'https://example.com',

  dotStyle: 'square',
  dotColor: '#000000',
  useGradient: false,
  gradient: {
    type: 'linear',
    rotation: 0,
    color1: '#000000',
    color2: '#2563eb'
  },

  bgEnabled: true,
  bgColor: '#ffffff',

  cornerSquareStyle: 'square',
  cornerDotStyle: 'square',

  errorCorrectionLevel: 'M',

  logoUrl: null,

  size: 1000,
  fileExt: 'png'
};

import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import QRCodeStyling from 'qr-code-styling';
import { QRCodeConfig } from '../types';

interface Props {
  config: QRCodeConfig;
  className?: string;
}

export interface QRCodeHandle {
  download: () => void;
}

const QRCodeRenderer = forwardRef<QRCodeHandle, Props>(({ config, className }, ref) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const qrCode = useRef<QRCodeStyling | null>(null);

  useImperativeHandle(ref, () => ({
    download: async () => {
      if (!qrCode.current) return;
      // When downloading, we apply the requested high-res size
      const currentOptions = (qrCode.current as any)._options; // Access internal options if needed, but we can just update

      // Update with full size for download
      qrCode.current.update({
          width: config.size,
          height: config.size
      });

      await qrCode.current.download({ 
        name: `qr-studio-${Date.now()}`, 
        extension: config.fileExt 
      });

      // Revert to preview size
      qrCode.current.update({
          width: 280,
          height: 280
      });
    }
  }));

  // Initialize
  useEffect(() => {
    if (!qrCode.current) {
        qrCode.current = new QRCodeStyling({
            width: 280, // Set to 280 to fit the max-w-[280px] container in App.tsx
            height: 280,
            type: "svg",
            data: config.value,
            image: config.logoUrl || undefined,
            qrOptions: {
                errorCorrectionLevel: config.errorCorrectionLevel
            },
            dotsOptions: {
                color: config.dotColor,
                type: config.dotStyle
            },
            backgroundOptions: {
                color: config.bgEnabled ? config.bgColor : 'transparent',
            },
            imageOptions: {
                crossOrigin: "anonymous",
                margin: 5
            }
        });
        if (containerRef.current) {
            containerRef.current.innerHTML = '';
            qrCode.current.append(containerRef.current);
        }
    }
  }, []);

  // Update
  useEffect(() => {
    if (!qrCode.current) return;

    const options: any = {
        width: 280, // Preview size
        height: 280,
        data: config.value,
        image: config.logoUrl || undefined,
        qrOptions: {
            errorCorrectionLevel: config.errorCorrectionLevel
        },
        dotsOptions: {
            type: config.dotStyle,
            color: config.dotColor
        },
        backgroundOptions: {
             color: config.bgEnabled ? config.bgColor : 'transparent',
        },
        cornersSquareOptions: {
            type: config.cornerSquareStyle,
            color: config.useGradient ? undefined : config.dotColor 
        },
        cornersDotOptions: {
            type: config.cornerDotStyle,
            color: config.useGradient ? undefined : config.dotColor
        }
    };

    // Apply Gradient
    if (config.useGradient) {
        const gradient = {
            type: config.gradient.type,
            rotation: (config.gradient.rotation * Math.PI) / 180,
            colorStops: [
                { offset: 0, color: config.gradient.color1 },
                { offset: 1, color: config.gradient.color2 }
            ]
        };
        options.dotsOptions.gradient = gradient;
        options.cornersSquareOptions.gradient = gradient;
        options.cornersDotOptions.gradient = gradient;

        // Remove solid colors so gradient shows
        delete options.dotsOptions.color;
        delete options.cornersSquareOptions.color;
        delete options.cornersDotOptions.color;
    } else {
        // IMPORTANT: Explicitly clear gradient when switching back to solid
        // qr-code-styling does a deep merge, so we must unset these
        options.dotsOptions.gradient = undefined;
        options.cornersSquareOptions.gradient = undefined;
        options.cornersDotOptions.gradient = undefined;
    }

    qrCode.current.update(options);

  }, [config]);

  return (
    <div ref={containerRef} className={className} id="canvas-container"></div>
  );
});

QRCodeRenderer.displayName = "QRCodeRenderer";
export default QRCodeRenderer;

import React, { useState, useEffect } from 'react';
import { 
  QRCodeConfig, QRType, DotType, CornerType, GradientType, ErrorCorrectionLevel
} from '../types';
import { ColorPicker } from './ColorPicker';
