        default:
            return (
                <div>
                    <label className={labelClass}>Website URL</label>
                    <input 
                        type="text" 
                        className={inputClass} 
                        value={config.value} 
                        onChange={e => setConfig({...config, value: e.target.value})}
                        placeholder="https://example.com" 
                    />
                </div>
