             <button className="p-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors">
                <Settings2 size={20} />
             </button>
          </div>
       </header>

       {/* Main Content Grid */}
       <div className="max-w-7xl mx-auto p-4 md:p-8 grid lg:grid-cols-12 gap-6 lg:gap-10 items-start w-full">

          {/* Left Column: Settings */}
          <div className="lg:col-span-7 w-full min-w-0 order-2 lg:order-1">
             <Sidebar config={config} setConfig={setConfig} />
          </div>

          {/* Right Column: Preview */}
          <div className="lg:col-span-5 w-full min-w-0 order-1 lg:order-2 lg:sticky lg:top-24">

             {/* Dark Preview Card */}
             <div className="bg-slate-900 rounded-3xl shadow-2xl shadow-slate-900/20 overflow-hidden relative">

                {/* Status Bar */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-slate-800">
                   <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Live Preview</span>
                   <div className="flex gap-1.5">
                      <div className="w-2 h-2 rounded-full bg-red-500"></div>
                      <div className="w-2 h-2 rounded-full bg-amber-500"></div>
                      <div className="w-2 h-2 rounded-full bg-green-500"></div>
                   </div>
                </div>

                {/* Canvas Area */}
                <div className="p-8 flex flex-col items-center justify-center min-h-[350px] bg-slate-800/50 relative">
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-[280px] aspect-square bg-brand-500/20 blur-[80px] rounded-full pointer-events-none"></div>
                    <div className={`relative w-full max-w-[280px] aspect-square rounded-2xl p-4 z-10 flex items-center justify-center transition-all duration-300
                        ${config.bgEnabled ? 'bg-white shadow-lg border border-slate-200/50' : 'bg-transparent border border-transparent'}
                    `}>
                        <QRCodeRenderer ref={qrRef} config={config} className="w-full h-full flex items-center justify-center" />
                    </div>
                </div>

                {/* Download Options */}
                <div className="bg-white p-5 space-y-5">

                    {/* Size Presets */}
                    <div>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2 block">Quick Size</span>
                        <div className="flex flex-wrap gap-2">
                            {presetSizes.map(size => (
                                <button
                                    key={size}
                                    onClick={() => setConfig({...config, size})}
                                    className={`flex-1 min-w-[70px] py-2 rounded-lg text-[10px] font-bold border transition-all
                                    ${config.size === size 
                                        ? 'bg-brand-50 border-brand-500 text-brand-600' 
                                        : 'bg-white border-slate-200 text-slate-500 hover:border-brand-200 hover:text-brand-600'}`}
                                >
                                    {size}x
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Size Slider */}
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Custom Size</span>
                            <span className="text-[10px] font-mono font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded">{config.size}px</span>
                        </div>
                        <input 
                           type="range" min="250" max="2000" step="50" 
                           value={config.size} 
                           onChange={(e) => setConfig({...config, size: parseInt(e.target.value)})}
                           className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-brand-600 hover:bg-slate-300 transition-colors"
                        />
                    </div>

                    <div className="h-px bg-slate-100 w-full"></div>

                    {/* Download Button Row */}
                    <div className="flex gap-3 pt-1">
                         <div className="relative w-1/3">
                            <select 
                                value={config.fileExt}
                                onChange={(e) => setConfig({...config, fileExt: e.target.value as FileExtension})}
                                className="w-full bg-slate-50 border-2 border-slate-100 text-slate-700 text-sm font-bold rounded-xl focus:border-brand-500 block p-3 outline-none appearance-none transition-colors hover:border-slate-300"
                            >
                                <option value="png">PNG</option>
                                <option value="jpeg">JPG</option>
                                <option value="svg">SVG</option>
                                <option value="webp">WEBP</option>
                            </select>
                            <ChevronDown className="absolute right-3 top-3.5 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                        <button 
                            onClick={handleDownload}
                            className="w-2/3 text-white bg-brand-600 hover:bg-brand-700 active:scale-[0.98] font-bold rounded-xl text-sm px-4 py-3 shadow-lg shadow-brand-500/30 flex items-center justify-center gap-2 transition-all"
                        >
                            <Download size={16} /> Download QR
                        </button>
                    </div>
                </div>

             </div>

             <p className="text-center text-[10px] text-slate-400 font-medium mt-4">100% Secure & Client-side Generation</p>
          </div>

       </div>
    </div>
  );
};

export default App;

export enum QRType {
  WEBSITE = 'website',
  TEXT = 'text',
  WIFI = 'wifi',
  VCARD = 'vcard',
  PHONE = 'phone',
  LOCATION = 'location',
  CALENDAR = 'calendar',
  BUSINESS = 'business',
  FACEBOOK = 'facebook',
  INSTAGRAM = 'instagram',
  WHATSAPP = 'whatsapp',
  YOUTUBE = 'youtube'
}

export type DotType = 'square' | 'dots' | 'rounded' | 'classy' | 'classy-rounded' | 'extra-rounded';
export type CornerType = 'square' | 'dot' | 'extra-rounded';
export type GradientType = 'linear' | 'radial';
export type FileExtension = 'png' | 'jpeg' | 'svg' | 'webp';
export type ErrorCorrectionLevel = 'L' | 'M' | 'Q' | 'H';

export interface GradientConfig {
  type: GradientType;
  rotation: number;
  color1: string;
  color2: string;
}

export interface QRCodeConfig {
  // Content
  type: QRType;
  value: string;

  // Design - Dots
  dotStyle: DotType;
  dotColor: string;
  useGradient: boolean;
  gradient: GradientConfig;

  // Design - Background
  bgEnabled: boolean;
  bgType: 'color' | 'image';
  bgColor: string;
  bgImage: string | null;
  bgOpacity: number;

  // Design - Corners
  cornerSquareStyle: CornerType; // 'square' | 'dot' | 'extra-rounded'
  cornerDotStyle: CornerType;    // 'square' | 'dot'

  // Configuration
  errorCorrectionLevel: ErrorCorrectionLevel;

  // Logo
  logoUrl: string | null;

  // Meta
  size: number;
  fileExt: FileExtension;
}

export const DEFAULT_CONFIG: QRCodeConfig = {
  type: QRType.WEBSITE,
  value: 'https://example.com',

  dotStyle: 'square',
  dotColor: '#2563eb',
  useGradient: true,
  gradient: {
    type: 'linear',
    rotation: 135,
    color1: '#2563eb',
    color2: '#4f46e5'
  },

  bgEnabled: true,
  bgType: 'color',
  bgColor: '#ffffff',
  bgImage: null,
  bgOpacity: 1,

  cornerSquareStyle: 'square',
  cornerDotStyle: 'square',

  errorCorrectionLevel: 'M',

  logoUrl: null,

  size: 1000,
  fileExt: 'png'
};
